export function getTripPackage(slug) {
  return tripPackages[slug] || null;
}

export function getDiscountRule(packageData, travelers) {
  if (!packageData || !Number.isFinite(travelers) || travelers < 1) {
    return { label: "No Discount", percent: 0 };
  }
  const { couple, family, group } = packageData.discounts;
  if (travelers >= group.min) return { label: "Group Discount", percent: group.percent };
  if (travelers >= family.min && travelers <= family.max) return { label: "Family Discount", percent: family.percent };
  if (travelers >= couple.min && travelers <= couple.max) return { label: "Couple Discount", percent: couple.percent };
  return { label: "No Discount", percent: 0 };
}

export function calculateTripPrice(packageData, travelers) {
  const base = packageData.basePricePerPerson;
  const { percent, label } = getDiscountRule(packageData, travelers);
  const discountedPerPerson = Math.round(base * (1 - percent / 100));
  const total = discountedPerPerson * travelers;
  const savings = (base - discountedPerPerson) * travelers;
  return { label, discountPercent: percent, perPerson: discountedPerPerson, total, savings };
}
